     1→import { useState } from "react";
     2→import { useNavigate } from "react-router-dom";
     3→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     4→import { PageHeader } from "@/components/layout/PageHeader";
     5→
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Button } from "@/components/ui/button";
     9→import {
    10→  Tooltip,
    11→  TooltipContent,
    12→  TooltipProvider,
    13→  TooltipTrigger,
    14→} from "@/components/ui/tooltip";
    15→import { getAdminNavItems } from "@/config/navigation";
    16→import { useAuth } from "@/contexts/AuthContext";
    17→import { LoadingSpinner } from "@/components/ui/loading-spinner";
    18→import { Info as Info } from "lucide-react";
    19→import { toast } from "sonner";
    20→import { salonService } from "@/services/salonService";
    21→import { CreateSalonDto } from "@/types/salon";
    22→import { formatPhone, formatCNPJ, unformatCNPJ } from "@/utils/formatters";
    23→import { cnpjService } from "@/services/cnpjService";
    24→import { TimezoneCombobox } from "@/components/forms/TimezoneCombobox";
    25→import { trackSeverinoEvent } from "@/services/severinoService";
    26→
    27→interface SalonInfo {
    28→  nomeFantasia: string;
    29→  razaoSocial: string;
    30→  cnpj: string;
    31→  telefoneComercial: string;
    32→  emailContato: string;
    33→  nomeLinkUtil: string;
    34→  urlLinkUtil: string;
    35→  timezone: string;
    36→}
    37→
    38→export default function CreateSalonPage() {
    39→  const { user } = useAuth();
    40→  const navigate = useNavigate();
    41→  const [isLoading, setIsLoading] = useState(false);
    42→  const [isFetchingCNPJ, setIsFetchingCNPJ] = useState(false);
    43→  const [salonInfo, setSalonInfo] = useState<SalonInfo>({
    44→    nomeFantasia: "",
    45→    razaoSocial: "",
    46→    cnpj: "",
    47→    telefoneComercial: "",
    48→    emailContato: "",
    49→    nomeLinkUtil: "",
    50→    urlLinkUtil: "",
    51→    timezone: "America/Sao_Paulo",
    52→  });
    53→
    54→  const handleSalonInfoChange = async (
    55→    field: keyof SalonInfo,
    56→    value: string
    57→  ): Promise<void> => {
    58→    if (field === "cnpj") {
    59→      const formattedCNPJ = formatCNPJ(value);
    60→      setSalonInfo((prev) => ({ ...prev, cnpj: formattedCNPJ }));
    61→
    62→      // Verifica se o CNPJ está completo (14 dígitos)
    63→      const cleanCNPJ = unformatCNPJ(formattedCNPJ);
    64→      if (cleanCNPJ.length === 14 && !isFetchingCNPJ) {
    65→        setIsFetchingCNPJ(true);
    66→        try {
    67→          const cnpjData = await cnpjService.fetchCompanyData(cleanCNPJ);
    68→          if (cnpjData && cnpjData.razao_social) {
    69→            setSalonInfo((prev) => ({
    70→              ...prev,
    71→              razaoSocial: cnpjData.razao_social || prev.razaoSocial,
    72→              nomeFantasia:
    73→                prev.nomeFantasia ||
    74→                cnpjData.nome_fantasia ||
    75→                cnpjData.razao_social ||
    76→                "",
    77→            }));
    78→          }
    79→        } catch (error) {
    80→          // Silenciosamente ignora erros
    81→        } finally {
    82→          setIsFetchingCNPJ(false);
    83→        }
    84→      }
    85→    } else {
    86→      setSalonInfo((prev) => ({ ...prev, [field]: value }));
    87→    }
    88→  };
    89→
    90→  const handleCreateSalon = async (): Promise<void> => {
    91→    // Validação básica
    92→    if (!salonInfo.nomeFantasia) {
    93→      toast.error("Por favor, preencha o nome fantasia");
    94→      return;
    95→    }
    96→    if (!salonInfo.telefoneComercial) {
    97→      toast.error("Por favor, preencha o telefone");
    98→      return;
    99→    }
   100→
   101→    // Validar CNPJ se fornecido
   102→    if (salonInfo.cnpj && !salonService.validateCNPJ(salonInfo.cnpj)) {
   103→      toast.error("CNPJ inválido");
   104→      return;
   105→    }
   106→
   107→    setIsLoading(true);
   108→
   109→    try {
   110→      // Obter usuário atual do localStorage
   111→      const userStr = localStorage.getItem("currentUser");
   112→      const user = userStr ? JSON.parse(userStr) : null;
   113→
   114→      // Preparar dados para criação
   115→      const createData: CreateSalonDto = {
   116→        name: salonInfo.nomeFantasia,
   117→        slug: salonService.generateSlug(salonInfo.nomeFantasia),
   118→        phone: salonService.formatPhone(salonInfo.telefoneComercial),
   119→        email: salonInfo.emailContato || undefined,
   120→        responsible: salonInfo.razaoSocial || undefined,
   121→        cnpj: salonInfo.cnpj
   122→          ? salonService.formatCNPJ(salonInfo.cnpj)
   123→          : undefined,
   124→        timezone: salonInfo.timezone,
   125→        tenantId: user?.tenantId, // Usar tenantId do usuário se disponível
   126→      };
   127→
   128→      // Criar salão com rede
   129→      const result = await salonService.createWithNetwork(createData);
   130→
   131→      trackSeverinoEvent('cadastro_do_salao', {
   132→        descricao: `Salão cadastrado: ${salonInfo.nomeFantasia} (ID: ${result.salon.id})`,
   133→        nomeSalao: salonInfo.nomeFantasia,
   134→        salonId: result.salon.id,
   135→      });
   136→
   137→      toast.success("Salão cadastrado com sucesso e adicionado à sua rede!");
   138→
   139→      // Redirecionar para a lista de salões
   140→      navigate("/admin/salons");
   141→    } catch (error: any) {
   142→      const errorMessage =
   143→        error?.response?.data?.message || "Erro ao criar salão";
   144→      toast.error(errorMessage);
   145→    } finally {
   146→      setIsLoading(false);
   147→    }
   148→  };
   149→
   150→  return (
   151→    <EasySalonLayout
   152→      sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
   153→      sideNavTitle="Easy Salon"
   154→      sideNavSubtitle="Área Administrativa"
   155→    >
   156→      <PageHeader
   157→        title="Cadastrar Novo Salão"
   158→        subtitle="Crie um novo salão na plataforma"
   159→      />
   160→
   161→      <div className="bg-card border border-border rounded-lg">
   162→        <div className="p-6">
   163→          <div className="space-y-6">
   164→            <TooltipProvider>
   165→              <div className="space-y-2">
   166→                <Label htmlFor="nomeFantasia">
   167→                  Nome Fantasia (como seus clientes o conhecem) *
   168→                </Label>
   169→                <Input
   170→                  id="nomeFantasia"
   171→                  value={salonInfo.nomeFantasia}
   172→                  onChange={(e) =>
   173→                    handleSalonInfoChange("nomeFantasia", e.target.value)
   174→                  }
   175→                  placeholder="Nome do seu salão"
   176→                  maxLength={100}
   177→                />
   178→                <div className="flex items-center gap-2 text-xs text-muted-foreground">
   179→                  <span>Esse nome será usado na URL pública do salão</span>
   180→                  <Tooltip>
   181→                    <TooltipTrigger asChild>
   182→                      <Info className="w-4 h-4 cursor-help" />
   183→                    </TooltipTrigger>
   184→                    <TooltipContent>
   185→                      <p>A URL pública do seu salão será:</p>
   186→                      <p className="font-mono">
   187→                        https://app.easysalon.com.br/
   188→                        {salonService.generateSlug(salonInfo.nomeFantasia) ||
   189→                          "nome-salao-nesse-formato"}
   190→                      </p>
   191→                    </TooltipContent>
   192→                  </Tooltip>
   193→                </div>
   194→              </div>
   195→            </TooltipProvider>
   196→
   197→            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   198→              <div className="space-y-2">
   199→                <Label htmlFor="cnpj">CNPJ</Label>
   200→                <div className="relative">
   201→                  <Input
   202→                    id="cnpj"
   203→                    value={salonInfo.cnpj}
   204→                    onChange={(e) =>
   205→                      handleSalonInfoChange("cnpj", e.target.value)
   206→                    }
   207→                    placeholder="XX.XXX.XXX/XXXX-XX"
   208→                    maxLength={18}
   209→                  />
   210→                  {isFetchingCNPJ && (
   211→                    <div className="absolute right-2 top-1/2 -translate-y-1/2">
   212→                      <LoadingSpinner size="sm" inline />
   213→                    </div>
   214→                  )}
   215→                </div>
   216→              </div>
   217→
   218→              <div className="space-y-2">
   219→                <Label htmlFor="razaoSocial">Razão Social</Label>
   220→                <Input
   221→                  id="razaoSocial"
   222→                  value={salonInfo.razaoSocial}
   223→                  onChange={(e) =>
   224→                    handleSalonInfoChange("razaoSocial", e.target.value)
   225→                  }
   226→                  placeholder="Razão social da empresa"
   227→                  maxLength={150}
   228→                />
   229→              </div>
   230→            </div>
   231→
   232→            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   233→              <div className="space-y-2">
   234→                <Label htmlFor="telefoneComercial">Telefone/WhatsApp *</Label>
   235→                <Input
   236→                  id="telefoneComercial"
   237→                  value={salonInfo.telefoneComercial}
   238→                  onChange={(e) =>
   239→                    handleSalonInfoChange(
   240→                      "telefoneComercial",
   241→                      formatPhone(e.target.value)
   242→                    )
   243→                  }
   244→                  placeholder="(XX) XXXXX-XXXX"
   245→                  maxLength={15}
   246→                />
   247→              </div>
   248→
   249→              <div className="space-y-2">
   250→                <Label htmlFor="emailContato">E-mail de Contato</Label>
   251→                <Input
   252→                  id="emailContato"
   253→                  type="email"
   254→                  value={salonInfo.emailContato}
   255→                  onChange={(e) =>
   256→                    handleSalonInfoChange("emailContato", e.target.value)
   257→                  }
   258→                  placeholder="contato@seusalao.com"
   259→                  maxLength={100}
   260→                />
   261→              </div>
   262→            </div>
   263→
   264→            <div className="space-y-2">
   265→              <div className="flex items-center gap-2">
   266→                <Label htmlFor="timezone">Localidade *</Label>
   267→                <TooltipProvider>
   268→                  <Tooltip>
   269→                    <TooltipTrigger asChild>
   270→                      <Info className="h-4 w-4 text-muted-foreground cursor-help" />
   271→                    </TooltipTrigger>
   272→                    <TooltipContent>
   273→                      <p className="max-w-xs">
   274→                        Selecione a localidade do seu salão. Isso garante que os
   275→                        horários de agendamento sejam exibidos corretamente para
   276→                        clientes em qualquer parte do mundo.
   277→                      </p>
   278→                    </TooltipContent>
   279→                  </Tooltip>
   280→                </TooltipProvider>
   281→              </div>
   282→              <TimezoneCombobox
   283→                value={salonInfo.timezone}
   284→                onValueChange={(value) =>
   285→                  handleSalonInfoChange("timezone", value)
   286→                }
   287→              />
   288→            </div>
   289→
   290→            <div className="space-y-4">
   291→              <Label className="text-lg font-semibold">
   292→                Link útil (Ex: Site)
   293→              </Label>
   294→              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   295→                <div className="space-y-2">
   296→                  <Label htmlFor="nomeLinkUtil">Nome do link</Label>
   297→                  <Input
   298→                    id="nomeLinkUtil"
   299→                    value={salonInfo.nomeLinkUtil}
   300→                    onChange={(e) =>
   301→                      handleSalonInfoChange("nomeLinkUtil", e.target.value)
   302→                    }
   303→                    placeholder="Site, Instagram, Facebook..."
   304→                    maxLength={50}
   305→                  />
   306→                </div>
   307→
   308→                <div className="space-y-2">
   309→                  <Label htmlFor="urlLinkUtil">URL</Label>
   310→                  <Input
   311→                    id="urlLinkUtil"
   312→                    value={salonInfo.urlLinkUtil}
   313→                    onChange={(e) =>
   314→                      handleSalonInfoChange("urlLinkUtil", e.target.value)
   315→                    }
   316→                    placeholder="https://seusite.com"
   317→                    maxLength={200}
   318→                  />
   319→                </div>
   320→              </div>
   321→            </div>
   322→          </div>
   323→
   324→          <div className="flex justify-end mt-8 pt-6 border-t">
   325→            <Button
   326→              onClick={handleCreateSalon}
   327→              disabled={isLoading}
   328→              className="bg-primary hover:bg-primary/90 text-primary-foreground px-8"
   329→            >
   330→              {isLoading ? (
   331→                <>
   332→                  <LoadingSpinner size="sm" inline className="mr-2" />
   333→                  Criando...
   334→                </>
   335→              ) : (
   336→                "Criar Salão"
   337→              )}
   338→            </Button>
   339→          </div>
   340→        </div>
   341→      </div>
   342→    </EasySalonLayout>
   343→  );
   344→}
