    10→export function TimezoneCombobox({ value, onValueChange, disabled }: TimezoneComboboxProps) {
    11→  const options = TIMEZONES.map((tz) => ({
    12→    value: tz.value,
    13→    label: `${tz.label} - ${tz.country} (${tz.offset})`,
    14→  }));
    15→
    16→  return (
    17→    <SelectPopover
    18→      value={value}
    19→      onValueChange={onValueChange}
    20→      options={options}
    21→      placeholder="Selecione o fuso horário"
    22→      searchable
    23→      searchPlaceholder="Buscar fuso horário..."
    24→      disabled={disabled}
    25→      className="salon-input"
    26→    />
    27→  );
    28→}
